use Storable;
use CGI::Cookie;

sub session_handler {
    my $session_id = CGI::Cookie::fetch("session_id");
    my $session_data = retrieve("/tmp/sess_$session_id");
    if (!$session_data) {
        $session_data = {};
        nstore($session_data, "/tmp/sess_$session_id");
    }
    return $session_data;
}

sub store_session {
    my $session_id = CGI::Cookie::fetch("session_id");
    my $session_data = shift;
    nstore($session_data, "/tmp/sess_$session_id");
}
